def redact_full_text(text: str | None) -> str:
    return shared_redact_full_text(text)


def parse_ms(value):
    try:
        return int(value)
    except Exception:
        return None


def iso_from_ms(value):
    ms = parse_ms(value)
    if ms is None:
        return now_iso()
    return dt.datetime.fromtimestamp(ms / 1000, dt.timezone.utc).isoformat()


def socket_listening(host: str, port: int, timeout=0.5) -> bool:
    try:
        with socket.create_connection((host, port), timeout=timeout):
            return True
    except OSError:
        return False


def url_listening(url: str, timeout=0.5) -> bool:
    parsed = urlparse(url)
    if not parsed.hostname:
        return False
    port = parsed.port or (443 if parsed.scheme == "https" else 80)
    return socket_listening(parsed.hostname, port, timeout)


def json_array_contains(raw, needle) -> int:
    """SQLite UDF for exact membership in JSON-array-ish text fields."""
    needle = str(needle or "").strip()
    if not needle or raw is None:
        return 0
    try:
        parsed = json.loads(str(raw))
        if isinstance(parsed, list):
            return 1 if needle in {str(item) for item in parsed} else 0
    except Exception:
        pass
    legacy_items = [item.strip() for item in str(raw).split(",") if item.strip()]
    return 1 if needle in legacy_items else 0


def db() -> sqlite3.Connection:
    conn = sqlite3.connect(DB_PATH, timeout=30, isolation_level=None)
    conn.row_factory = sqlite3.Row
    conn.create_function("agentops_json_array_contains", 2, json_array_contains)
    conn.execute("PRAGMA foreign_keys = ON")
    conn.execute("PRAGMA busy_timeout = 30000")
    conn.execute("PRAGMA journal_mode = WAL")
    conn.execute("PRAGMA synchronous = NORMAL")
    return conn


def rows_to_dicts(rows):
    return [dict(r) for r in rows]


def path_segment(path: str, index: int = -1) -> str:
    """Return a URL-decoded path segment for IDs carried in REST paths."""
    return unquote(path.split("/")[index])


def qs_int(qs: dict, name: str, default: int, minimum: int, maximum: int) -> int:
    try:
        value = int((qs.get(name) or [str(default)])[0])
    except (TypeError, ValueError):
        value = default
    return min(max(value, minimum), maximum)


def qs_bool(qs: dict, name: str, default: bool = False) -> bool:
    value = (qs.get(name) or [str(default).lower()])[0]
    return str(value).strip().lower() in {"1", "true", "yes", "on"}


def jsonable_clone(value):
    return json.loads(json.dumps(value, ensure_ascii=False, default=str))


