def hermes_models(conn) -> dict:
    status = hermes_status()
    refresh_runtime_connectors(conn, status)
    agnes = status["agnesfallback"]
    url = agnes["gateway_url"].rstrip("/") + "/v1/models"
    started = dt.datetime.now(dt.timezone.utc)
    try:
        with urlopen(Request(url, method="GET"), timeout=8) as res:
            payload = json.loads(res.read().decode("utf-8"))
        latency = int((dt.datetime.now(dt.timezone.utc) - started).total_seconds() * 1000)
        runtime_event(conn, "rtc_agnesfallback_openai_api", "models_probe", "completed", model_name="agnesfallback", latency_ms=latency, output_summary="Agnesfallback models endpoint responded.", raw_payload_hash=stable_hash(payload))
        audit(conn, "system", "hermes-models", "runtime.models", "runtime_connectors", "rtc_agnesfallback_openai_api", None, {"status": "completed"}, {"payload_hash": stable_hash(payload)})
        conn.commit()
        return {"provider": "agnesfallback", "status": "available", "gateway_url": agnes["gateway_url"], "models": payload.get("data", payload)}
    except Exception as exc:
        err = redact_text(str(exc), 240)
        runtime_event(conn, "rtc_agnesfallback_openai_api", "models_probe", "unavailable", error_message=err)
        audit(conn, "system", "hermes-models", "runtime.models.unavailable", "runtime_connectors", "rtc_agnesfallback_openai_api", None, {"status": "unavailable"}, {"error": err})
        conn.commit()
        return {"provider": "agnesfallback", "status": "unavailable", "gateway_url": agnes["gateway_url"], "models": [], "error": err}


def is_local_or_private_url(value: str) -> bool:
    parsed = urlparse(value or "")
    host = parsed.hostname or ""
    if host in {"localhost", "127.0.0.1", "::1"}:
        return True
    try:
        ip = ipaddress.ip_address(host)
        return ip.is_private or ip.is_loopback
    except ValueError:
        return host.endswith(".local") or host.endswith(".internal")


def dify_config() -> dict:
    base_url = os.environ.get("DIFY_API_BASE_URL", os.environ.get("DIFY_BASE_URL", "http://127.0.0.1:8088/v1")).strip().rstrip("/")
    mode = os.environ.get("DIFY_TRUST_MODE", "").strip()
    if not mode:
        mode = "local_dify" if is_local_or_private_url(base_url) else "cloud_dify"
    api_key = os.environ.get("DIFY_KB_API_KEY", os.environ.get("DIFY_API_KEY", "")).strip()
    dataset_id = os.environ.get("DIFY_DATASET_ID", "").strip()
    allow_real_upload = os.environ.get("DIFY_ALLOW_REAL_UPLOAD", "").strip().lower() in ("1", "true", "yes")
    require_approval_env = os.environ.get("DIFY_REQUIRE_APPROVAL", "").strip().lower()
    if require_approval_env:
        require_approval = require_approval_env not in ("0", "false", "no")
    else:
        require_approval = mode != "local_dify"
    return {
        "provider": "dify",
        "api_base_url": base_url,
        "trust_mode": coerce_choice(mode, {"local_dify", "customer_server_dify", "cloud_dify"}, "cloud_dify"),
        "has_api_key": bool(api_key),
        "api_key": api_key,
        "dataset_id": dataset_id,
        "has_dataset_id": bool(dataset_id),
        "allow_real_upload": allow_real_upload,
        "require_approval": require_approval,
        "same_trust_domain": is_local_or_private_url(base_url),
        "api_listening": url_listening(base_url),
    }


def dify_status(conn=None) -> dict:
    cfg = dify_config()
    status = "available" if cfg["api_listening"] and cfg["has_api_key"] else "dry_run" if cfg["api_listening"] else "unavailable"
    payload = {
        "provider": "dify",
        "connector_id": "conn_dify_knowledge",
        "api_base_url": cfg["api_base_url"],
        "trust_mode": cfg["trust_mode"],
        "same_trust_domain": cfg["same_trust_domain"],
        "api_listening": cfg["api_listening"],
        "configured": cfg["api_listening"] and cfg["has_api_key"] and cfg["has_dataset_id"],
        "has_api_key": cfg["has_api_key"],
        "has_dataset_id": cfg["has_dataset_id"],
        "allow_real_upload": cfg["allow_real_upload"],
        "require_approval": cfg["require_approval"],
        "dry_run_default": not cfg["allow_real_upload"],
        "write_behavior": "local/private Dify may run with confirm_upload; cloud or cross-domain upload requires approval.",
    }
    if conn:
        conn.execute(
            "UPDATE connectors SET status=?, last_checked_at=?, last_error=?, writeback_allowed=?, updated_at=? WHERE connector_id='conn_dify_knowledge'",
            (
                status,
                now_iso(),
                None if payload["configured"] else "Dify needs reachable API, API key and dataset id for live upload.",
                1 if cfg["allow_real_upload"] else 0,
                now_iso(),
            ),
        )
    return payload


def ensure_dify_agent_task(conn, body: dict):
    now = now_iso()
    agent_id = body.get("agent_id") or "agt_gw_kb_builder"
    ensure_gateway_agent(conn, agent_id, name="Knowledge Base Builder Agent", role="Knowledge Base Builder", runtime_type="mock")
    task_id = body.get("task_id") or stable_id("tsk_dify_upload", body.get("dataset_id") or dify_config()["dataset_id"] or "local", body.get("document_name") or "document")
    if not conn.execute("SELECT 1 FROM tasks WHERE task_id=?", (task_id,)).fetchone():
        upsert_task(conn, {
            "task_id": task_id,
            "title": body.get("task_title") or "Dify knowledge base ingestion",
            "description": "Agent-managed Dify document ingestion. MIS stores only summary, hashes, ids and audit evidence.",
            "requester_id": body.get("requester_id") or "usr_founder",
            "owner_agent_id": agent_id,
            "collaborator_agent_ids": json.dumps([], ensure_ascii=False),
            "status": "planned",
            "priority": coerce_choice(body.get("priority"), VALID_PRIORITIES, "high"),
            "due_date": None,
            "acceptance_criteria": "Dify receives the approved document, and MIS records run/tool/eval/audit without storing raw credentials or full source text.",
            "risk_level": coerce_choice(body.get("risk_level"), VALID_RISK_LEVELS, "high"),
            "budget_limit_usd": float(body.get("budget_limit_usd") or 1.0),
            "created_at": now,
            "updated_at": now,
        }, "dify-connector")
    return agent_id, task_id


def approval_is_approved(conn, approval_id: str | None) -> bool:
    if not approval_id:
        return False
    row = conn.execute("SELECT decision FROM approvals WHERE approval_id=?", (approval_id,)).fetchone()
    return bool(row and row["decision"] == "approved")


def dify_upload_risk_level(cfg: dict) -> str:
    return "medium" if cfg["trust_mode"] == "local_dify" else "high"


def dify_upload_action_args(dataset_id: str | None, document_name: str, text_hash: str, cfg: dict) -> dict:
    return {
        "provider": "dify",
        "operation": "knowledge.upload_text",
        "dataset_id": redact_text(dataset_id or "", 80),
        "document_name": document_name,
        "text_hash": text_hash,
        "trust_mode": cfg["trust_mode"],
        "same_trust_domain": cfg["same_trust_domain"],
        "raw_text_stored_in_mis": False,
        "requires_prepared_action_for_external_write": True,
    }


def dify_prepared_action_payload(conn, body: dict, cfg: dict, agent_id: str, task_id: str, dataset_id: str, document_name: str, text_hash: str) -> dict:
    now = now_iso()
    run_id = body.get("run_id") or stable_id("run_dify_upload_prepare", dataset_id, document_name, text_hash)
    tool_call_id = body.get("tool_call_id") or stable_id("tc_dify_upload_prepare", run_id)
    action_args = dify_upload_action_args(dataset_id, document_name, text_hash, cfg)
    run_row = {
        "run_id": run_id,
        "task_id": task_id,
        "agent_id": agent_id,
        "runtime_type": "mock",
        "status": "waiting_approval",
        "started_at": now,
        "ended_at": None,
        "duration_ms": None,
        "input_summary": f"Dify upload prepared action text_hash={text_hash[:16]} dataset_id={redact_text(dataset_id, 80)}",
        "output_summary": "Dify live upload paused before provider call; exact prepared action approval is required.",
        "model_provider": "dify",
        "model_name": "knowledge-api",
        "input_tokens": 0,
        "output_tokens": 0,
        "reasoning_tokens": 0,
        "cost_usd": 0.0,
        "error_type": None,
        "error_message": None,
        "trace_id": body.get("trace_id"),
        "parent_run_id": body.get("parent_run_id"),
        "delegation_id": body.get("delegation_id") or "dify:knowledge-upload",
        "approval_required": 1,
        "created_at": now,
    }
    tool_row = {
        "tool_call_id": tool_call_id,
        "run_id": run_id,
        "agent_id": agent_id,
        "tool_name": "dify.knowledge.upload",
        "tool_version": "v1",
        "tool_category": "custom",
        "normalized_args_json": json.dumps(action_args, ensure_ascii=False, sort_keys=True),
        "target_resource": f"dify://datasets/{redact_text(dataset_id, 80)}/documents/[pending]",
        "risk_level": dify_upload_risk_level(cfg),
        "status": "waiting_approval",
        "result_summary": "Prepared Dify upload action only; no provider side effect has occurred.",
        "side_effect_id": None,
        "started_at": now,
        "ended_at": None,
        "created_at": now,
    }
    upsert_run(conn, run_row, "dify-connector", {"text_hash": text_hash, "raw_text_omitted": True, "prepared_action_required": True})
    upsert_tool_call(conn, tool_row, "dify-connector", {"text_hash": text_hash, "raw_text_omitted": True, "prepared_action_required": True})
    approval_wall, _status = agent_gateway_prepare_action(conn, {
        "workspace_id": body.get("workspace_id") or "local-demo",
        "run_id": run_id,
        "tool_call_id": tool_call_id,
        "agent_id": agent_id,
        "requested_by_agent_id": agent_id,
        "action_type": "dify.knowledge.upload",
        "args": action_args,
        "target_resource": tool_row["target_resource"],
        "risk_level": tool_row["risk_level"],
        "policy_version": "approval-wall-v1",
        "checkpoint": {
            "run_id": run_id,
            "tool_call_id": tool_call_id,
            "connector_id": "conn_dify_knowledge",
            "checkpoint": "before_dify_document_create_by_text",
            "text_hash": text_hash,
        },
        "idempotency_key": body.get("idempotency_key") or stable_hash({
            "connector": "dify",
            "dataset_id": redact_text(dataset_id, 80),
            "document_name": document_name,
            "text_hash": text_hash,
        })[:32],
        "reason": body.get("approval_reason") or "Dify knowledge-base upload is an external write and requires exact prepared-action approval before provider execution.",
    })
    runtime_event(conn, "rtc_agent_gateway_local", "dify.upload_text.prepared_action_required", "waiting_approval", run_id=run_id, task_id=task_id, agent_id=agent_id, input_summary=f"Dify upload paused text_hash={text_hash[:16]}", output_summary="Prepared action created; live provider upload not executed.", raw_payload_hash=text_hash)
    audit(conn, "agent", agent_id, "dify.upload_text.prepared_action_required", "runs", run_id, None, {"status": "waiting_approval"}, {"approval_id": (approval_wall.get("approval") or {}).get("approval_id"), "prepared_action_id": (approval_wall.get("prepared_action") or {}).get("action_id"), "text_hash": text_hash, "raw_text_omitted": True, "token_omitted": True})
    return {
        "run_id": run_id,
        "tool_call_id": tool_call_id,
        "action_args": action_args,
        "approval_wall": approval_wall,
    }


def dify_prepared_action_resume_gate(conn, body: dict, expected_args: dict) -> tuple[sqlite3.Row | None, dict | None]:
    action_id = prepared_action_id_from_request(body)
    row = conn.execute("SELECT * FROM prepared_actions WHERE action_id=?", (action_id,)).fetchone() if action_id else None
    approval = conn.execute("SELECT * FROM approvals WHERE approval_id=?", (row["approval_id"],)).fetchone() if row else None
    gate_error = prepared_action_resume_gate_error(
        action_id=action_id,
        row=row,
        approval=approval,
        expected_args=expected_args,
        expected_action_type="dify.knowledge.upload",
        comparable_fields=("provider", "operation", "dataset_id", "document_name", "text_hash"),
        missing_error="dify_prepared_action_required",
        missing_message="Dify live upload requires a prepared_action_id created by the Approval Wall.",
        approval_message="Dify upload can execute only after the linked prepared action approval is approved.",
    )
    if gate_error:
        return None, gate_error
    return row, None


def dify_create_document_by_text(conn, body: dict) -> dict:
    cfg = dify_config()
    status_payload = dify_status(conn)
    confirm = bool(body.get("confirm_upload"))
    dataset_id = body.get("dataset_id") or cfg["dataset_id"]
    document_name = redact_text(body.get("document_name") or body.get("name") or "AgentOps MIS document", 120)
    text = body.get("text") or body.get("document_text") or ""
    text_hash = stable_hash(text)
    text_preview = redact_text(text, 200)
    agent_id, task_id = ensure_dify_agent_task(conn, {**body, "dataset_id": dataset_id, "document_name": document_name})
    action_args = dify_upload_action_args(dataset_id, document_name, text_hash, cfg)
    approval_ok = not cfg["require_approval"] or approval_is_approved(conn, body.get("approval_id"))
    live_prerequisites_met = bool(cfg["allow_real_upload"] and confirm and cfg["has_api_key"] and dataset_id and text)
    plan = {
        "provider": "dify",
        "mode": cfg["trust_mode"],
        "dry_run": True,
        "live_upload_performed": False,
        "configured": status_payload["configured"],
        "would_post": f"{cfg['api_base_url']}/datasets/{dataset_id or '[dataset_id]'}/document/create-by-text",
        "document_name": document_name,
        "text_preview": text_preview,
        "text_hash": text_hash,
        "requires": {
            "DIFY_ALLOW_REAL_UPLOAD": True,
            "confirm_upload": True,
            "DIFY_KB_API_KEY": True,
            "DIFY_DATASET_ID_or_body_dataset_id": True,
            "approved_approval_id": cfg["require_approval"],
            "prepared_action_id": True,
        },
        "trust_boundary": {
            "same_trust_domain": cfg["same_trust_domain"],
            "require_approval": cfg["require_approval"],
            "approval_ok": approval_ok,
            "prepared_action_required_for_live_upload": True,
        },
        "note": "MIS never stores the full document text or API key. Live upload sends the provided text to Dify only when explicitly allowed.",
    }
    if not live_prerequisites_met:
        runtime_event(conn, "rtc_agent_gateway_local", "dify.upload_text.dry_run", "planned", task_id=task_id, agent_id=agent_id, input_summary=f"Dify upload dry-run text_hash={text_hash[:16]}", raw_payload_hash=text_hash)
        audit(conn, "agent", agent_id, "dify.upload_text.dry_run", "connectors", "conn_dify_knowledge", None, plan, {"confirm_upload": confirm, "approval_id": body.get("approval_id"), "text_hash": text_hash})
        conn.commit()
        return plan

    prepared_row, gate_error = dify_prepared_action_resume_gate(conn, body, action_args)
    if gate_error:
        if gate_error.get("error") == "dify_prepared_action_required":
            prepared = dify_prepared_action_payload(conn, body, cfg, agent_id, task_id, dataset_id, document_name, text_hash)
            conn.commit()
            return build_prepared_action_waiting_response(
                base={
                    **plan,
                    "run_id": prepared["run_id"],
                    "tool_call_id": prepared["tool_call_id"],
                },
                approval_wall=prepared["approval_wall"],
                reason="dify_external_write_prepared_action_required",
                resume_instruction="POST /api/integrations/dify/upload-text with prepared_action_id={prepared_action_id}",
            )
        runtime_event(conn, "rtc_agent_gateway_local", "dify.upload_text.prepared_action_blocked", "blocked", task_id=task_id, agent_id=agent_id, input_summary=f"Dify upload blocked text_hash={text_hash[:16]}", output_summary=gate_error.get("error"), raw_payload_hash=text_hash)
        audit(conn, "agent", agent_id, "dify.upload_text.prepared_action_blocked", "connectors", "conn_dify_knowledge", None, gate_error, {"text_hash": text_hash, "raw_text_omitted": True, "token_omitted": True})
        conn.commit()
        return build_prepared_action_blocked_response(base=plan, gate_error=gate_error)

    started_iso = now_iso()
    started = dt.datetime.now(dt.timezone.utc)
    run_id = prepared_row["run_id"] if prepared_row else body.get("run_id") or stable_id("run_dify_upload", dataset_id, document_name, dt.datetime.now(dt.timezone.utc).strftime("%Y%m%d%H%M%S"))
    payload = {
        "name": document_name,
        "text": text,
        "indexing_technique": body.get("indexing_technique") or "high_quality",
        "process_rule": body.get("process_rule") or {"mode": "automatic"},
    }
    ok = False
    error = None
    response_hash = None
    document_id = None
    try:
        req = Request(
            f"{cfg['api_base_url']}/datasets/{dataset_id}/document/create-by-text",
            data=json.dumps(payload, ensure_ascii=False).encode("utf-8"),
            method="POST",
            headers={"Content-Type": "application/json", "Authorization": f"Bearer {cfg['api_key']}"},
        )
        with urlopen(req, timeout=60) as res:
            response = json.loads(res.read().decode("utf-8"))
        response_hash = stable_hash(response)
        document = response.get("document") or response.get("data") or response
        document_id = document.get("id") if isinstance(document, dict) else None
        ok = True
    except Exception as exc:
        error = redact_text(str(exc), 240)

    duration = int((dt.datetime.now(dt.timezone.utc) - started).total_seconds() * 1000)
    row = {
        "run_id": run_id,
        "task_id": task_id,
        "agent_id": agent_id,
        "runtime_type": "mock",
        "status": "completed" if ok else "failed",
        "started_at": started_iso,
        "ended_at": now_iso(),
        "duration_ms": duration,
        "input_summary": f"Dify upload text_hash={text_hash[:16]} dataset_id={redact_text(dataset_id, 80)}",
        "output_summary": f"Dify document created: {document_id}" if ok else "Dify document upload failed.",
        "model_provider": "dify",
        "model_name": "knowledge-api",
        "input_tokens": 0,
        "output_tokens": 0,
        "reasoning_tokens": 0,
        "cost_usd": 0.0,
        "error_type": None if ok else "DifyUploadFailed",
        "error_message": error,
        "trace_id": body.get("trace_id"),
        "parent_run_id": body.get("parent_run_id"),
        "delegation_id": body.get("delegation_id") or "dify:knowledge-upload",
        "approval_required": 0 if ok else 1,
        "created_at": started_iso,
    }
    upsert_run(conn, row, "dify-connector", {"text_hash": text_hash, "response_hash": response_hash, "document_id": document_id, "dataset_id": redact_text(dataset_id, 80)})
    tool_row = {
        "tool_call_id": prepared_row["tool_call_id"] if prepared_row else body.get("tool_call_id") or stable_id("tc_dify_upload", run_id),
        "run_id": run_id,
        "agent_id": agent_id,
        "tool_name": "dify.knowledge.upload",
        "tool_version": "v1",
        "tool_category": "custom",
        "normalized_args_json": json.dumps({**action_args, "approval_id": body.get("approval_id"), "prepared_action_id": prepared_row["action_id"] if prepared_row else body.get("prepared_action_id")}, ensure_ascii=False, sort_keys=True),
        "target_resource": f"dify://datasets/{redact_text(dataset_id, 80)}/documents/{document_id or 'unknown'}",
        "risk_level": dify_upload_risk_level(cfg),
        "status": "completed" if ok else "failed",
        "result_summary": row["output_summary"],
        "side_effect_id": document_id,
        "started_at": started_iso,
        "ended_at": row["ended_at"],
        "created_at": started_iso,
    }
    upsert_tool_call(conn, tool_row, "dify-connector", {"text_hash": text_hash, "response_hash": response_hash, "raw_text_omitted": True})
    upsert_evaluation(conn, quality_gate_for_run(row), "dify-connector")
    runtime_event(conn, "rtc_agent_gateway_local", "dify.upload_text", "completed" if ok else "failed", run_id=run_id, task_id=task_id, agent_id=agent_id, latency_ms=duration, input_summary=f"Dify text upload text_hash={text_hash[:16]}", output_summary=row["output_summary"], error_message=error, raw_payload_hash=response_hash or text_hash)
    if ok and prepared_row:
        resume_payload, resume_status = agent_gateway_resume_prepared_action(conn, prepared_row["action_id"], build_prepared_action_provider_resume_request(
            prepared_row,
            provider_side_effect_id=document_id or stable_id("dify_document", run_id, text_hash),
            result_summary=row["output_summary"],
        ))
    else:
        resume_payload, resume_status = None, None
    audit(conn, "agent", agent_id, "dify.upload_text", "runs", run_id, None, {"status": row["status"], "document_id": document_id}, {"text_hash": text_hash, "dataset_id": redact_text(dataset_id, 80), "approval_id": prepared_row["approval_id"] if prepared_row else body.get("approval_id"), "prepared_action_id": prepared_row["action_id"] if prepared_row else body.get("prepared_action_id"), "trust_mode": cfg["trust_mode"], "token_omitted": True})
    conn.commit()
    return {
        "provider": "dify",
        "mode": cfg["trust_mode"],
        "dry_run": False,
        "live_upload_performed": True,
        "ok": ok,
        "task_id": task_id,
        "run_id": run_id,
        "tool_call_id": tool_row["tool_call_id"],
        "document_id": document_id,
        "dataset_id": redact_text(dataset_id, 80),
        "duration_ms": duration,
        "text_hash": text_hash,
        "output_summary": row["output_summary"],
        "error": error,
        **build_prepared_action_provider_result_fields(prepared_row, resume_payload, resume_status),
    }


