def agnesfallback_cli_probe(conn, body: dict) -> dict:
    cfg = hermes_runtime_config()
    agnes = agnesfallback_config()
    prompt = "请只回复 AGNESFALLBACK_OK，不要解释。"
    connector_id = "rtc_agnesfallback_cli"
    confirm = bool(body.get("confirm_run"))
    plan = {
        "provider": "agnesfallback",
        "mode": "cli_probe",
        "dry_run": True,
        "would_run": agnesfallback_cli_command(agnes, "[FIXED_SAFE_PROMPT]"),
        "prompt_hash": stable_hash(prompt),
        "requires": {"HERMES_ALLOW_REAL_RUN": True, "confirm_run": True},
        "note": "Extra CLI args are empty by default. Use AGNESFALLBACK_CLI_EXTRA_ARGS only for explicit local recording mode.",
    }
    refresh_runtime_connectors(conn)
    if not (cfg["allow_real_run"] and confirm):
        runtime_event(conn, connector_id, "cli_probe_dry_run", "planned", prompt_hash=stable_hash(prompt), input_summary="Agnesfallback CLI fixed probe dry-run.")
        audit(conn, "system", "agnesfallback-cli", "runtime.cli_probe.dry_run", "runtime_connectors", connector_id, None, plan, {"confirm_run": confirm})
        conn.commit()
        return plan
    agent_id, task_id = ensure_agnesfallback_agent_task(conn, "cli")
    action_args = runtime_probe_action_args("agnesfallback", "cli_probe", connector_id, stable_hash(prompt), agnes["binary_path"])
    prepared_row, gate_error = runtime_probe_prepared_action_resume_gate(conn, body, action_args)
    if gate_error:
        if gate_error.get("error") == "runtime_probe_prepared_action_required":
            return runtime_probe_prepared_action_required_response(conn, body, provider="agnesfallback", mode="cli_probe", connector_id=connector_id, agent_id=agent_id, task_id=task_id, runtime_type="hermes", prompt_hash=stable_hash(prompt), target_resource=agnes["binary_path"], risk_level="medium")
        runtime_event(conn, connector_id, "cli_probe_prepared_action_blocked", "blocked", task_id=task_id, agent_id=agent_id, prompt_hash=stable_hash(prompt), output_summary=gate_error.get("error"), raw_payload_hash=stable_hash(prompt))
        audit(conn, "system", "agnesfallback-cli", "runtime.cli_probe.prepared_action_blocked", "runtime_connectors", connector_id, None, gate_error, {"prompt_hash": stable_hash(prompt), "token_omitted": True})
        conn.commit()
        return runtime_probe_blocked_payload(provider="agnesfallback", mode="cli_probe", gate_error=gate_error)
    started_iso = now_iso()
    started = dt.datetime.now(dt.timezone.utc)
    ok = False
    visible = None
    error = None
    try:
        proc = subprocess.run(agnesfallback_cli_command(agnes, prompt), capture_output=True, text=True, timeout=180, check=False)
        visible = redact_text((proc.stdout or "").strip(), 200)
        ok = proc.returncode == 0 and visible == "AGNESFALLBACK_OK"
        if not ok:
            error = redact_text(proc.stderr or visible or f"exit={proc.returncode}", 240)
    except Exception as exc:
        error = redact_text(str(exc), 240)
    duration = int((dt.datetime.now(dt.timezone.utc) - started).total_seconds() * 1000)
    run_id = prepared_row["run_id"]
    row = {
        "run_id": run_id,
        "task_id": task_id,
        "agent_id": agent_id,
        "runtime_type": "hermes",
        "status": "completed" if ok else "failed",
        "started_at": started_iso,
        "ended_at": now_iso(),
        "duration_ms": duration,
        "input_summary": f"Agnesfallback CLI fixed probe prompt_hash={stable_hash(prompt)[:16]}",
        "output_summary": "Agnesfallback CLI returned AGNESFALLBACK_OK." if ok else "Agnesfallback CLI probe failed.",
        "model_provider": "agnesfallback",
        "model_name": "agnesfallback",
        "input_tokens": 0,
        "output_tokens": 0,
        "reasoning_tokens": 0,
        "cost_usd": 0.0,
        "error_type": None if ok else "AgnesfallbackCliProbeFailed",
        "error_message": error,
        "trace_id": None,
        "parent_run_id": None,
        "delegation_id": "agnesfallback:cli",
        "approval_required": 0,
        "created_at": started_iso,
    }
    upsert_run(conn, row, "agnesfallback-cli", {"prompt_hash": stable_hash(prompt)})
    upsert_evaluation(conn, quality_gate_for_run(row), "agnesfallback-cli")
    runtime_event(conn, connector_id, "cli_probe", "completed" if ok else "failed", run_id=run_id, task_id=task_id, agent_id=agent_id, model_name="agnesfallback", latency_ms=duration, prompt_hash=stable_hash(prompt), output_summary=visible, error_message=error, raw_payload_hash=stable_hash({"visible": visible, "error": error}))
    resume_payload, resume_status = agent_gateway_resume_prepared_action(conn, prepared_row["action_id"], build_prepared_action_provider_resume_request(
        prepared_row,
        provider_side_effect_id=stable_id("agnesfallback_cli_probe", run_id, stable_hash(visible or error or "")),
        result_summary=row["output_summary"],
    ))
    audit(conn, "system", "agnesfallback-cli", "runtime.cli_probe", "runs", run_id, None, {"status": row["status"]}, {"prompt_hash": stable_hash(prompt), "confirmed": True, "prepared_action_id": prepared_row["action_id"], "approval_id": prepared_row["approval_id"], "token_omitted": True})
    conn.commit()
    return {"provider": "agnesfallback", "mode": "cli_probe", "dry_run": False, "live_probe_performed": True, "ok": ok, "run_id": run_id, "duration_ms": duration, "output_summary": row["output_summary"], "error": error, **build_prepared_action_provider_result_fields(prepared_row, resume_payload, resume_status)}


def agnesfallback_chat_completion_probe(conn, body: dict) -> dict:
    cfg = hermes_runtime_config()
    agnes = agnesfallback_config()
    prompt = "请只回复 HERMES_AGNES_API_OK，不要解释。"
    connector_id = "rtc_agnesfallback_openai_api"
    confirm = bool(body.get("confirm_run"))
    plan = {
        "provider": "agnesfallback",
        "mode": "openai_compatible",
        "dry_run": True,
        "would_post": agnes["gateway_url"].rstrip("/") + "/v1/chat/completions",
        "prompt_hash": stable_hash(prompt),
        "requires": {"HERMES_ALLOW_REAL_RUN": True, "confirm_run": True},
    }
    refresh_runtime_connectors(conn)
    if not (cfg["allow_real_run"] and confirm):
        runtime_event(conn, connector_id, "chat_completion_probe_dry_run", "planned", prompt_hash=stable_hash(prompt), input_summary="Agnesfallback API fixed probe dry-run.")
        audit(conn, "system", "agnesfallback-api", "runtime.chat_completion_probe.dry_run", "runtime_connectors", connector_id, None, plan, {"confirm_run": confirm})
        conn.commit()
        return plan
    agent_id, task_id = ensure_agnesfallback_agent_task(conn, "api")
    target_resource = agnes["gateway_url"].rstrip("/") + "/v1/chat/completions"
    action_args = runtime_probe_action_args("agnesfallback", "openai_compatible", connector_id, stable_hash(prompt), target_resource)
    prepared_row, gate_error = runtime_probe_prepared_action_resume_gate(conn, body, action_args)
    if gate_error:
        if gate_error.get("error") == "runtime_probe_prepared_action_required":
            return runtime_probe_prepared_action_required_response(conn, body, provider="agnesfallback", mode="openai_compatible", connector_id=connector_id, agent_id=agent_id, task_id=task_id, runtime_type="hermes", prompt_hash=stable_hash(prompt), target_resource=target_resource, risk_level="medium")
        runtime_event(conn, connector_id, "chat_completion_probe_prepared_action_blocked", "blocked", task_id=task_id, agent_id=agent_id, prompt_hash=stable_hash(prompt), output_summary=gate_error.get("error"), raw_payload_hash=stable_hash(prompt))
        audit(conn, "system", "agnesfallback-api", "runtime.chat_completion_probe.prepared_action_blocked", "runtime_connectors", connector_id, None, gate_error, {"prompt_hash": stable_hash(prompt), "token_omitted": True})
        conn.commit()
        return runtime_probe_blocked_payload(provider="agnesfallback", mode="openai_compatible", gate_error=gate_error)
    started_iso = now_iso()
    started = dt.datetime.now(dt.timezone.utc)
    payload = {"model": "agnesfallback", "messages": [{"role": "user", "content": prompt}], "temperature": 0}
    ok = False
    visible = None
    error = None
    response_hash = None
    try:
        req = Request(
            target_resource,
            data=json.dumps(payload, ensure_ascii=False).encode("utf-8"),
            method="POST",
            headers={"Content-Type": "application/json"},
        )
        with urlopen(req, timeout=180) as res:
            response = json.loads(res.read().decode("utf-8"))
        response_hash = stable_hash(response)
        visible = (((response.get("choices") or [{}])[0].get("message") or {}).get("content") or "").strip()
        visible = redact_text(visible, 200)
        ok = visible == "HERMES_AGNES_API_OK"
        if not ok:
            error = redact_text(visible or "unexpected response", 240)
    except Exception as exc:
        error = redact_text(str(exc), 240)
    duration = int((dt.datetime.now(dt.timezone.utc) - started).total_seconds() * 1000)
    run_id = prepared_row["run_id"]
    row = {
        "run_id": run_id,
        "task_id": task_id,
        "agent_id": agent_id,
        "runtime_type": "hermes",
        "status": "completed" if ok else "failed",
        "started_at": started_iso,
        "ended_at": now_iso(),
        "duration_ms": duration,
        "input_summary": f"Agnesfallback OpenAI-compatible fixed probe prompt_hash={stable_hash(prompt)[:16]}",
        "output_summary": "Agnesfallback API returned HERMES_AGNES_API_OK." if ok else "Agnesfallback API probe failed.",
        "model_provider": "agnesfallback",
        "model_name": "agnesfallback",
        "input_tokens": 0,
        "output_tokens": 0,
        "reasoning_tokens": 0,
        "cost_usd": 0.0,
        "error_type": None if ok else "AgnesfallbackApiProbeFailed",
        "error_message": error,
        "trace_id": None,
        "parent_run_id": None,
        "delegation_id": "agnesfallback:openai-compatible",
        "approval_required": 0,
        "created_at": started_iso,
    }
    upsert_run(conn, row, "agnesfallback-api", {"prompt_hash": stable_hash(prompt), "raw_payload_hash": response_hash})
    upsert_evaluation(conn, quality_gate_for_run(row), "agnesfallback-api")
    runtime_event(conn, connector_id, "chat_completion_probe", "completed" if ok else "failed", run_id=run_id, task_id=task_id, agent_id=agent_id, model_name="agnesfallback", latency_ms=duration, prompt_hash=stable_hash(prompt), output_summary=visible, error_message=error, raw_payload_hash=response_hash)
    resume_payload, resume_status = agent_gateway_resume_prepared_action(conn, prepared_row["action_id"], build_prepared_action_provider_resume_request(
        prepared_row,
        provider_side_effect_id=stable_id("agnesfallback_api_probe", run_id, response_hash or stable_hash(visible or error or "")),
        result_summary=row["output_summary"],
    ))
    audit(conn, "system", "agnesfallback-api", "runtime.chat_completion_probe", "runs", run_id, None, {"status": row["status"]}, {"prompt_hash": stable_hash(prompt), "confirmed": True, "prepared_action_id": prepared_row["action_id"], "approval_id": prepared_row["approval_id"], "token_omitted": True})
    conn.commit()
    return {"provider": "agnesfallback", "mode": "openai_compatible", "dry_run": False, "live_probe_performed": True, "ok": ok, "run_id": run_id, "duration_ms": duration, "output_summary": row["output_summary"], "error": error, **build_prepared_action_provider_result_fields(prepared_row, resume_payload, resume_status)}


