def scalar_count(conn: sqlite3.Connection, sql: str, params=()) -> int:
    row = conn.execute(sql, params).fetchone()
    return int((row[0] if row else 0) or 0)


def status_counts(conn: sqlite3.Connection, table: str, valid_statuses: set[str] | None = None) -> dict:
    if table not in {"tasks", "runs", "workflow_jobs"}:
        return {}
    rows = rows_to_dicts(conn.execute(f"SELECT status, COUNT(*) AS count FROM {table} GROUP BY status").fetchall())
    counts = {str(row.get("status") or "unknown"): int(row.get("count") or 0) for row in rows}
    if valid_statuses:
        for status in valid_statuses:
            counts.setdefault(status, 0)
    return dict(sorted(counts.items()))


def safe_commander_readiness_snapshot(conn: sqlite3.Connection, headers) -> tuple[dict, dict]:
    readiness: dict = {}
    worker: dict = {}
    try:
        readiness = local_readiness(conn, headers, refresh_runtime=False)
    except Exception as exc:
        readiness = {"status": "unknown", "error": redact_text(str(exc), 160)}
    finally:
        conn.rollback()
    try:
        worker = worker_status(conn, refresh_runtime=False)
    except Exception as exc:
        worker = {"status": "unknown", "error": redact_text(str(exc), 160)}
    finally:
        conn.rollback()
    return readiness, worker


REPO_MAP_EXCLUDED_DIRS = {
    ".git",
    ".venv",
    "__pycache__",
    ".pytest_cache",
    ".mypy_cache",
    ".ruff_cache",
    "node_modules",
    "dist",
    "build",
    ".next",
    ".agentops_runtime",
}

REPO_MAP_EXCLUDED_SUFFIXES = {
    ".db",
    ".sqlite",
    ".sqlite3",
    ".png",
    ".jpg",
    ".jpeg",
    ".gif",
    ".webp",
    ".ico",
    ".pdf",
    ".zip",
    ".tar",
    ".gz",
    ".mp4",
    ".mov",
    ".lock",
    ".log",
}

REPO_MAP_INCLUDED_SUFFIXES = {
    ".py",
    ".ts",
    ".tsx",
    ".js",
    ".jsx",
    ".json",
    ".md",
    ".yml",
    ".yaml",
    ".toml",
    ".txt",
    ".css",
    ".html",
    ".sh",
}

REPO_MAP_DEFAULT_MAX_FILE_BYTES = 240_000
REPO_MAP_CORE_MAX_FILE_BYTES = 2_000_000
REPO_MAP_LARGE_CORE_FILES = {
    "server.py",
    "agentops_mis_cli/agentops.py",
}


def commander_safe_text(value, limit=180) -> str:
    redacted = redact_text(value, limit)
    redacted = re.sub(r"(?i)bearer\s+\[REDACTED\]", "[SECRET_REDACTED]", redacted)
    redacted = re.sub(r"(?i)\b(?:agtok|agtsess)_[a-z0-9._\-]+\b", "[SECRET_REDACTED]", redacted)
    return redacted[:limit]


def repo_map_query_tokens(query: str) -> list[str]:
    tokens = []
    for token in re.findall(r"[A-Za-z0-9_./:-]+", query.lower()):
        token = token.strip("./:-_")
        if len(token) >= 2 and token not in {"the", "and", "for", "with", "into", "from", "this", "that"}:
            tokens.append(token)
    deduped = []
    for token in tokens:
        if token not in deduped:
            deduped.append(token)
    return deduped[:24]


def repo_map_file_allowed(path: Path) -> bool:
    rel = path.relative_to(ROOT)
    parts = set(rel.parts)
    if parts & REPO_MAP_EXCLUDED_DIRS:
        return False
    if path.name.startswith(".env"):
        return False
    if any(part.startswith(".agentops") for part in rel.parts):
        return False
    if path.suffix.lower() in REPO_MAP_EXCLUDED_SUFFIXES:
        return False
    if path.suffix.lower() not in REPO_MAP_INCLUDED_SUFFIXES:
        return False
    max_bytes = REPO_MAP_CORE_MAX_FILE_BYTES if rel.as_posix() in REPO_MAP_LARGE_CORE_FILES else REPO_MAP_DEFAULT_MAX_FILE_BYTES
    try:
        if path.stat().st_size > max_bytes:
            return False
    except OSError:
        return False
    return True


def iter_repo_map_candidate_files(candidate_limit: int):
    yielded = 0
    for root, dirnames, filenames in os.walk(ROOT):
        dirnames[:] = sorted(
            dirname for dirname in dirnames
            if dirname not in REPO_MAP_EXCLUDED_DIRS and not dirname.startswith(".agentops")
        )
        for filename in sorted(filenames):
            path = Path(root) / filename
            if not repo_map_file_allowed(path):
                continue
            yield path
            yielded += 1
            if yielded >= candidate_limit:
                return


def repo_map_symbol_lines(text: str) -> list[dict]:
    symbols = []
    pattern = re.compile(r"^\s*(?:def|class|async\s+def|function|export\s+function|const|let|var)\s+([A-Za-z_][A-Za-z0-9_]*)", re.MULTILINE)
    for match in pattern.finditer(text[:120_000]):
        line_no = text.count("\n", 0, match.start()) + 1
        symbols.append({"name": commander_safe_text(match.group(1), 120), "line": line_no})
        if len(symbols) >= 12:
            break
    return symbols


def repo_map_snippets(lines: list[str], query_tokens: list[str], max_snippets: int = 3) -> list[dict]:
    snippets = []
    lower_tokens = [token.lower() for token in query_tokens]
    for idx, line in enumerate(lines, start=1):
        hay = line.lower()
        if lower_tokens and not any(token in hay for token in lower_tokens):
            continue
        if len(line.strip()) < 2:
            continue
        snippets.append({
            "line": idx,
            "text": commander_safe_text(line.strip(), 220),
        })
        if len(snippets) >= max_snippets:
            break
    return snippets


def commander_repo_map(qs=None, headers=None) -> dict:
    qs = qs or {}
    query = commander_safe_text((qs.get("q") or qs.get("query") or [""])[0], 240)
    query_tokens = repo_map_query_tokens(query)
    limit = qs_int(qs, "limit", 12, 1, 40)
    char_budget = qs_int(qs, "char_budget", 8000, 1200, 24000)
    if "budget" in qs and "char_budget" not in qs:
        char_budget = qs_int(qs, "budget", 8000, 1200, 24000)
    candidate_limit = qs_int(qs, "candidate_limit", 360, 40, 1200)
    files = []
    skipped = {"excluded": 0, "too_large_or_binary": 0, "unmatched": 0}
    for path in iter_repo_map_candidate_files(candidate_limit):
        rel = path.relative_to(ROOT).as_posix()
        try:
            raw = path.read_text(encoding="utf-8")
        except UnicodeDecodeError:
            skipped["too_large_or_binary"] += 1
            continue
        except OSError:
            skipped["excluded"] += 1
            continue
        lowered_path = rel.lower()
        lowered = raw.lower()
        title = path.stem.replace("_", " ").replace("-", " ")
        score = 0
        matched_fields = []
        for token in query_tokens:
            path_hits = lowered_path.count(token)
            content_hits = min(lowered.count(token), 20)
            if path_hits:
                score += path_hits * 24
                if "path" not in matched_fields:
                    matched_fields.append("path")
            if token in title.lower():
                score += 16
                if "title" not in matched_fields:
                    matched_fields.append("title")
            if content_hits:
                score += content_hits * 2
                if "content" not in matched_fields:
                    matched_fields.append("content")
        if not query_tokens:
            score = 1 if rel in {"PROJECT_SPEC.md", "AGENT_WORKFLOW.md", "BASE_INDEX.md"} or rel.startswith("docs/project/") else 0
            if score:
                matched_fields.append("baseline")
        if score <= 0:
            skipped["unmatched"] += 1
            continue
        lines = raw.splitlines()
        symbols = repo_map_symbol_lines(raw)
        symbol_hits = [
            item for item in symbols
            if any(token in str(item.get("name") or "").lower() for token in query_tokens)
        ]
        if symbol_hits:
            score += len(symbol_hits) * 18
            if "symbol" not in matched_fields:
                matched_fields.append("symbol")
        snippets = repo_map_snippets(lines, query_tokens)
        files.append({
            "path": rel,
            "score": score,
            "matched_fields": matched_fields,
            "symbols": symbol_hits[:6] or symbols[:4],
            "snippets": snippets,
            "line_count": len(lines),
            "content_hash": stable_hash(raw),
            "source_provenance": {
                "source": "repo_file",
                "root": "repository",
                "path": rel,
                "ranking_inputs": ["query_tokens", "path", "title", "symbols", "redacted_content"],
                "raw_content_returned": False,
                "token_omitted": True,
            },
            "rank_reason": commander_safe_text(
                f"score={score}; matched={','.join(matched_fields) or 'none'}; tokens={','.join(query_tokens[:6]) or 'baseline'}",
                240,
            ),
            "token_omitted": True,
        })
    ranked = sorted(files, key=lambda item: (-int(item["score"]), item["path"]))
    selected = []
    used_chars = 0
    for item in ranked:
        estimate = len(item["path"]) + sum(len(snippet.get("text") or "") for snippet in item.get("snippets") or []) + 160
        if selected and used_chars + estimate > char_budget:
            continue
        selected.append(item)
        used_chars += estimate
        if len(selected) >= limit:
            break
    return {
        "provider": "agentops-commander",
        "operation": "repo_map",
        "status": "ready" if selected else "empty",
        "query": query,
        "query_tokens": query_tokens,
        "limit": limit,
        "char_budget": char_budget,
        "used_chars_estimate": used_chars,
        "candidate_count": len(ranked),
        "selected_count": len(selected),
        "files": selected,
        "skipped": skipped,
        "ranking": {
            "deterministic": True,
            "sort": "score desc, path asc",
            "score_version": "repo-map-localizer-v2",
            "token_omitted": True,
        },
        "contract": "read-only repo localization for coding work packages; scans tracked-style repo text paths, returns redacted snippets plus hashes, and does not mutate ledger or execute commands",
        "safety": {
            "read_only": True,
            "ledger_mutated": False,
            "live_execution_performed": False,
            "raw_file_bodies_returned": False,
            "token_omitted": True,
        },
        "token_omitted": True,
    }


def commander_project_board(conn: sqlite3.Connection, headers, qs=None) -> dict:
    qs = qs or {}
    readiness, worker = safe_commander_readiness_snapshot(conn, headers)
    adapter_payload = worker_adapter_readiness(conn, refresh=False)
    conn.rollback()
    workspace_id = normalize_workspace_id(headers.get("X-AgentOps-Workspace-Id") or "local-demo")
    live_acceptance = live_acceptance_readiness(conn, workspace_id)
    live_acceptance_summary = live_acceptance.get("summary") or {}
    project_id = commander_safe_text((qs.get("project_id") or [""])[0], 120)
    plan_id = commander_safe_text((qs.get("plan_id") or [""])[0], 120)
    try:
        team_limit_raw = int((qs.get("limit") or ["25"])[0])
    except Exception:
        team_limit_raw = 25
    team_limit = min(max(team_limit_raw, 1), 100)
    team_readback = None
    team_board = None
    if project_id or plan_id:
        team_readback = commander_work_packages_readback(conn, {
            "workspace_id": [workspace_id],
            "project_id": [project_id],
            "plan_id": [plan_id],
            "status": ["all"],
            "limit": [str(team_limit)],
        }, headers)
        team_board = build_commander_team_board(
            packages=team_readback.get("work_packages") or [],
            workspace_id=workspace_id,
            project_id=project_id or None,
            plan_id=plan_id or None,
        )

    task_counts = status_counts(conn, "tasks", VALID_TASK_STATUSES)
    run_counts = status_counts(conn, "runs")
    workflow_counts = status_counts(conn, "workflow_jobs", {"queued", "running", "completed", "failed"})
    active_workflow_jobs = scalar_count(conn, "SELECT COUNT(*) FROM workflow_jobs WHERE status IN ('queued','running')")
    stuck_jobs = workflow_stuck_jobs(conn, threshold_sec=900, limit=10)
    recent_artifact_rows = rows_to_dicts(conn.execute(
        """SELECT artifact_id, task_id, run_id, artifact_type, title, created_at
        FROM artifacts
        ORDER BY created_at DESC
        LIMIT 8"""
    ).fetchall())
    for artifact in recent_artifact_rows:
        artifact["title"] = commander_safe_text(artifact.get("title"), 160)
    memory_candidate_count = scalar_count(conn, "SELECT COUNT(*) FROM memories WHERE review_status='candidate'")
    memory_review_counts = {
        str(row["review_status"]): int(row["count"] or 0)
        for row in conn.execute("SELECT review_status, COUNT(*) AS count FROM memories GROUP BY review_status").fetchall()
    }
    pending_approval_count = scalar_count(conn, "SELECT COUNT(*) FROM approvals WHERE decision='pending'")
    synthesis_lifecycle = commander_synthesis_lifecycle(conn, limit=5)
    synthesis_summary = synthesis_lifecycle.get("summary") or {}

    recent_tasks = rows_to_dicts(conn.execute(
        """SELECT task_id, title, status, owner_agent_id, priority, risk_level, created_at
        FROM tasks
        ORDER BY created_at DESC
        LIMIT 12"""
    ).fetchall())
    recent_work_packages = []
    for task in recent_tasks:
        latest_run = conn.execute(
            """SELECT run_id, status, created_at
            FROM runs
            WHERE task_id=?
            ORDER BY created_at DESC
            LIMIT 1""",
            (task["task_id"],),
        ).fetchone()
        recent_work_packages.append({
            "task_id": task.get("task_id"),
            "title": commander_safe_text(task.get("title"), 180),
            "status": task.get("status"),
            "owner_agent_id": task.get("owner_agent_id"),
            "priority": task.get("priority"),
            "risk": task.get("risk_level"),
            "created_at": task.get("created_at"),
            "latest_run": {
                "run_id": latest_run["run_id"],
                "status": latest_run["status"],
                "created_at": latest_run["created_at"],
            } if latest_run else None,
        })

    readiness_gates = {gate.get("id"): gate for gate in (readiness.get("gates") or []) if isinstance(gate, dict)}
    worker_fleet = worker.get("fleet_health") or readiness.get("worker_fleet_health") or {}
    adapter_summary = adapter_payload.get("summary") or readiness.get("adapter_readiness") or {}
    closed_loop_runs = int(((readiness.get("evidence") or {}).get("closed_loop_runs") or 0))
    approved_memory = int(memory_review_counts.get("approved") or 0)

    integration_gates = build_commander_project_board_gates(
        closed_loop_runs=closed_loop_runs,
        worker_status=worker,
        worker_fleet=worker_fleet,
        pending_approval_count=pending_approval_count,
        memory_candidate_count=memory_candidate_count,
        approved_memory_count=approved_memory,
        synthesis_lifecycle=synthesis_lifecycle,
        adapter_status=adapter_payload.get("status") or "unknown",
        adapter_summary=adapter_summary,
        live_acceptance_status=live_acceptance.get("status") or "unknown",
        live_acceptance_summary=live_acceptance_summary,
    )
    recommended_next_actions = commander_project_board_next_actions(integration_gates, readiness.get("next_actions") or [])
    board_status = commander_project_board_status(integration_gates)
    return {
        "provider": "agentops-commander",
        "operation": "project_board",
        "status": board_status,
        "token_omitted": True,
        "live_execution_performed": False,
        "workspace_id": workspace_id,
        "local_readiness": {
            "status": readiness.get("status") or "unknown",
            "ok": bool(readiness.get("ok")) if "ok" in readiness else None,
            "gate_count": len(readiness.get("gates") or []),
            "blocked_gates": [gate_id for gate_id, gate in readiness_gates.items() if not gate.get("ok")][:8],
        },
        "worker_status": {
            "status": worker.get("status") or "unknown",
            "running_workers": int(worker.get("running_workers") or 0),
            "pending_worker_tasks": int(worker.get("pending_worker_tasks") or 0),
            "stuck_worker_tasks": int(worker.get("stuck_worker_tasks") or 0),
            "remote_worker_count": int(worker.get("remote_worker_count") or 0),
            "fleet_overall": worker_fleet.get("overall"),
        },
        "counts": {
            "tasks_by_status": task_counts,
            "runs_by_status": run_counts,
            "workflow_jobs_by_status": workflow_counts,
            "pending_approvals": pending_approval_count,
            "active_workflow_jobs": active_workflow_jobs,
            "stuck_workflow_jobs": len(stuck_jobs),
            "recent_artifacts": len(recent_artifact_rows),
            "memory_candidates": memory_candidate_count,
            "synthesis_artifacts": synthesis_summary.get("synthesis_artifacts", 0),
            "synthesis_pending_reviews": synthesis_summary.get("pending_reviews", 0),
            "synthesis_promoted_deliveries": synthesis_summary.get("promoted_delivery_artifacts", 0),
            "live_acceptance_fresh": live_acceptance_summary.get("fresh", 0),
            "live_acceptance_latest_failed": live_acceptance_summary.get("latest_failed", 0),
            "live_acceptance_latest_incomplete": live_acceptance_summary.get("latest_incomplete", 0),
            "live_acceptance_missing": live_acceptance_summary.get("missing", 0),
            "live_acceptance_stale": live_acceptance_summary.get("stale", 0),
        },
        "synthesis_lifecycle": synthesis_lifecycle,
        "live_acceptance": {
            "status": live_acceptance.get("status") or "unknown",
            "summary": live_acceptance_summary,
            "adapters": {
                adapter: {
                    "status": item.get("status"),
                    "ok": item.get("ok"),
                    "latest_attempt": item.get("latest_attempt"),
                    "latest_passing": item.get("latest_passing"),
                    "active_attempt": item.get("active_attempt"),
                    "next_action": item.get("next_action"),
                    "token_omitted": True,
                }
                for adapter, item in (live_acceptance.get("adapters") or {}).items()
            },
            "safety": live_acceptance.get("safety") or {},
            "token_omitted": True,
            "live_execution_performed": False,
        },
        "recent_artifacts": recent_artifact_rows,
        "stuck_workflow_jobs": [{
            "job_id": job.get("job_id"),
            "workflow_type": job.get("workflow_type"),
            "status": job.get("status"),
            "age_sec": job.get("age_sec"),
            "result_task_id": job.get("result_task_id"),
            "result_run_id": job.get("result_run_id"),
        } for job in stuck_jobs],
        "recent_work_packages": recent_work_packages,
        "team_board": team_board,
        "team_board_filter": {
            "project_id": project_id or None,
            "plan_id": plan_id or None,
            "limit": team_limit,
            "applied": bool(project_id or plan_id),
        },
        "team_work_packages_summary": (team_readback or {}).get("summary"),
        "integration_gates": integration_gates,
        "recommended_next_actions": recommended_next_actions[:8],
        "safety": {
            "read_only": True,
            "ledger_mutated": False,
            "task_created": False,
            "run_created": False,
            "job_created": False,
            "token_omitted": True,
            "raw_prompt_omitted": True,
        },
    }



def command_center_overview(conn: sqlite3.Connection, headers, qs=None, auth_ctx: dict | None = None) -> dict:
    """Compatibility alias for the canonical operator command-center BFF."""
    payload = jsonable_clone(operator_command_center(conn, headers, qs, auth_ctx))
    payload["alias_operation"] = "command_center_overview"
    payload["canonical_operation"] = payload.get("operation")
    payload["canonical_endpoint"] = "/api/operator/command-center"
    return payload


